mapper.select:
SELECT *
FROM search_history
WHERE enterprise_id = #{enterpriseId}

    AND search_time >= #{startTime}


    AND search_time <= #{endTime}

ORDER BY search_time DESC, id DESC

mapper.delete:
DELETE
FROM search_history
WHERE enterprise_id = #{enterpriseId}
  AND search_time < #{beforeTime}

mapper.select:
SELECT COUNT(1)
FROM search_history
WHERE enterprise_id = #{enterpriseId}

SELECT COUNT(1)
FROM search_history
WHERE enterprise_id = #{enterpriseId}
  AND DATE(search_time) = #{statDate}
